INSERT INTO questions (id, user_id, tank_id, title, content, image_path, status, created_at, updated_at) VALUES
(1, 3, 1, 'Monte Carlo turning yellow after 3 weeks', 'Leaves pale yellow, dosing twice a week. CO2 + strong light.', NULL, 'open',     NOW(), NOW()),
(2, 4, 2, 'Brown algae on glass in new tank',         'New tank, diatoms on glass and stones. Any tips?',            NULL, 'resolved', NOW(), NOW()),
(3, 6, 4, 'Bucephalandra melting after moving',       'Moved bucephalandra to a new tank, some leaves melt. Normal?', NULL, 'open',    NOW(), NOW());
INSERT INTO answers (id, question_id, user_id, content, is_accepted, created_at, updated_at) VALUES
(1, 1, 2, 'Likely nutrient imbalance. Keep NO3 stable and ensure CO2 consistency.', 1, NOW(), NOW()),
(2, 1, 5, 'Also consider new-tank instability; do regular water changes.',          0, NOW(), NOW()),
(3, 2, 2, 'Diatoms are common in new tanks. Reduce light and increase water changes.', 1, NOW(), NOW()),
(4, 3, 2, 'Some melting can happen after changes. Keep parameters stable and avoid frequent moves.', 1, NOW(), NOW());
INSERT INTO posts (id, user_id, title, content, image_path, created_at, updated_at) VALUES
(1, 3, 'My first Iwagumi – 90 days journal',   'From bare glass to full carpet. Lessons about CO2, trimming, and algae control.', '/assets/img/demo_iwagumi.jpg', NOW(), NOW()),
(2, 2, 'Beginner guide to balanced fertilizing','Simple routine to feed plants without triggering algae. Example schedules inside.', NULL, NOW(), NOW()),
(3, 6, 'Admin Showcase tank – setup notes',     'Testing epiphytes (java fern, bolbitis) and stable CO2. Will update weekly.', NULL, NOW(), NOW());
INSERT INTO comments (id, post_id, user_id, content, created_at, updated_at) VALUES
(1, 1, 2, 'Great journal! Tracking NO3 is a big help for beginners.', NOW(), NOW()),
(2, 1, 4, 'Did you notice CO2 issues with fish after trims?',        NOW(), NOW()),
(3, 2, 5, 'This guide is super clear. Thanks!',                      NOW(), NOW()),
(4, 3, 2, 'Nice setup. Keep flow gentle for bolbitis and monitor algae early.', NOW(), NOW());
